fun solve(nums: Array<Long>): Long {
    val sorted = nums.sortedWith(Comparator { a, b -> a.abs.compareTo(b.abs) })
    val n = sorted.size
    var total = 0L
    for (i in 0 until n) {
        val target = 2 * sorted[i]
        var low = i + 1
        var high = n - 1
        var res = -1
        while (low <= high) {
            val mid = (low + high) / 2
            if (sorted[mid] <= target) {
                res = mid
                low = mid + 1
            } else {
                high = mid - 1
            }
        }
        if (res != -1) {
            total += (res - i).toLong()
        }
    }
    return total
}
